{
  "config": {
    "view": {
      "continuousWidth": 300,
      "continuousHeight": 300
    }
  },
  "data": {
    "url": "https://cdn.jsdelivr.net/npm/vega-datasets@v1.29.0/data/population.json"
  },
  "mark": {
    "type": "bar"
  },
  "encoding": {
    "color": {
      "field": "sex",
      "legend": {
        "labelExpr": "datum.value == 1 ? 'Male' : 'Female'",
        "title": "Sex"
      },
      "scale": {
        "domain": [
          1,
          2
        ],
        "range": [
          "steelblue",
          "salmon"
        ]
      },
      "type": "nominal"
    },
    "x": {
      "axis": {
        "format": "s",
        "labelExpr": "abs(datum.value)"
      },
      "field": "signed_people",
      "title": "Population",
      "type": "quantitative"
    },
    "y": {
      "field": "age",
      "sort": "descending",
      "title": "Age",
      "type": "ordinal"
    }
  },
  "height": 400,
  "params": [
    {
      "name": "year",
      "bind": {
        "input": "select",
        "options": [
          1850,
          1860,
          1870,
          1880,
          1890,
          1900,
          1910,
          1920,
          1930,
          1940,
          1950,
          1960,
          1970,
          1980,
          1990,
          2000
        ],
        "name": "Year "
      },
      "value": 1980
    }
  ],
  "title": "US Population by Age and Sex",
  "transform": [
    {
      "calculate": "datum.sex == 1 ? -datum.people : datum.people",
      "as": "signed_people"
    },
    {
      "filter": "(datum.year === year)"
    }
  ],
  "width": 600,
  "$schema": "https://vega.github.io/schema/vega-lite/v6.4.1.json"
}

